;◆イベント◆

; 初期発生イベント
events = []

;------------------------------------------------------------------------------
*event_1
;[exp] true

@delevent
@jump storage="main02.scn" target=*ruin_4

[eventoff]
;------------------------------------------------------------------------------
*event_2
;[exp] true

@eval exp='tf.arr = [3, 4]'
@wait time=300
@walk turn=w
@jump target=*_dead_end
;------------------------------------------------------------------------------
*event_3
;[exp] true

@eval exp='tf.arr = [2, 4]'
@wait time=300
@walk turn=n
@jump target=*_dead_end
;------------------------------------------------------------------------------
*event_4
;[exp] true

@eval exp='tf.arr = [2, 3]'
@wait time=300
@walk turn=s
@jump target=*_dead_end
;------------------------------------------------------------------------------
*_dead_end

@delevent
@wait time=300
[texton]
[if exp='game.map.events.has(tf.arr[0]) && game.map.events.has(tf.arr[1])']
	[マックス f=06]「Damn, is this a dead end?」[k]
[elsif exp='game.map.events.has(tf.arr[0]) || game.map.events.has(tf.arr[1])']
	[マックス f=10]「Damn, this one's no good either.」[k]
[else]
	@eval exp='game.party.minimumRecovery()'
	@jump storage="main02.scn" target=*ruin_5
[endif]
[textoff]

[eventoff]
